WITH c AS (INSERT INTO chapters (book_id, slug, title, position) VALUES ('f1bae824-5378-4152-b8d9-f25d730af107', 'luku-i-katalysaattori', 'Luku I — Katalysaattori', 1) RETURNING id) INSERT INTO sections (chapter_id, title, content, position) VALUES
((SELECT id FROM c), 'Katalysaattori', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteereista fossiilisiin polttoaineisiin Merenpohjassa, noin kahden miljardin vuoden ikäisessä kivessä, on ohut punainen raita. Geolog tuntee sen nimeltä: Red Bed Formation. Se kulkee maapallon ympäri kuin haava, kaivettu esiin eroosion toimesta paikoissa joita ei oltu miljoonia vuosia ennen ihmistä. Raita on rautaa — ruostunutta rautaa — ja se kertoo tarinan joka alkoi ennen kuin yksikään monisoluinen olento oli vielä olemassa. Se kertoo tarinan hapesta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ennen suuren hapettumistapahtuman alkua — noin 2,4 miljardia vuotta sitten — maapallon ilmakehässä oli happea häviävän vähän. Merissä oli runsaasti liuennutta rautaa. Elämä, jota oli jo yli miljardi vuotta, käytti energianlähteenään muita kemikaaleja: rikkiä, rautaa, yksinkertaisia orgaanisia yhdisteitä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Sitten syanobakteerit keksivät fotosynteesin, tai tarkemmin: ne kehittivät fotosynteesiä niin tehokkaaksi, että sen sivutuote — happi — alkoi kertyä mereen ja lopulta ilmakehään. Syanobakteerit eivät tienneet tekevänsä mitään mullistavaa. Ne vain hyödynsivät auringon valoa poikkeuksellisen tehokkaasti. Mutta tästä tehokkuudesta seurasi jotain jota kukaan ei olisi voinut ennakoida."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tehokkuus voi olla vaarallisempaa kuin tuhlaus — silloin kun sivuvaikutuksia ei tunneta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Happi on kemiallisesti aggressiivinen aine. Se reagoi lähes kaiken kanssa. Meressä oleva rauta hapettui ja vajosi pohjaan — siitä ne punaiset raidat kivessä. Ilmakehässä happi tuhosi metaanin, joka oli pitänyt maapallon lämpimänä. Seurauksena oli jääkausi jollaista maapallon historia ei ole kokenut ennen tai jälkeen: Huronian jääkausi, joka saattoi jäädyttää maapallon lähes kokonaan pinnasta ytimeen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja elämä? Valtaosa siitä kuoli. Happi oli myrkkyä lähes kaikille tuolloin eläneille organismeille. Ne olivat kehittyneet hapettomassa maailmassa, ja äkillinen muutos tuhosi niiden aineenvaihdunnan. Biologit arvioivat, että suurin osa tuon ajan lajeista hävisi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteerit olivat tuottaneet historian ensimmäisen massasukupuuton. Tietämättään. Tavoittelemattaan. Vain elämällä mahdollisimman tehokkaasti."}]}]}'::jsonb, 0),
((SELECT id FROM c), 'Mitä tuhosta jäi', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tarina ei pääty tuhoon. Se alkaa siitä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Happi ei ollut vain myrkky — se oli myös vallankumous. Organismeille jotka oppivat hyödyntämään sitä, happi avasi aineenvaihdunnallisen tehokkuuden jota aiempi elämä ei ollut koskaan kokenut. Aerobinen hengitys tuottaa jopa kahdeksantoistakertaisen määrän energiaa verrattuna anaerobisiin vaihtoehtoihin. Se on kuin siirtyisi kynttilästä sähkövalaistukseen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tästä energiabuumista seurasi jotain jota ei voinut ennakoida: monimutkaisuus alkoi olla mahdollista. Yksisoluiset organismit alkoivat muodostaa yhteisöjä. Yhteisöt alkoivat erikoistua. Erikoistuminen johti solujen työnjakoon. Ja noin 600 miljoonaa vuotta sitten — lähes kaksi miljardia vuotta jälkeen — räjähti käyntiin kambrinen eksplosio: elämänmuotojen kirjo, joka on siitä lähtien kasvanut katkoksitta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Jokainen monisoluinen olento maapallolle — jokainen kala, hyönteinen, puu, lintu, nisäkäs, ihminen — on syanobakteerien sivuvaikutuksen jälkeläinen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Happikatastrofi oli välttämätön ehto sille mitä seurasi. Ei riittävä ehto — moni asia olisi voinut mennä toisin. Mutta välttämätön."}]}]}'::jsonb, 1),
((SELECT id FROM c), 'Pitkä uni', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Nyt hypätään ajassa eteenpäin — mutta ei vielä ihmiseen asti."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kun monisoluinen elämä kukoisti, kasvillisuus levisi mantereille. Kivihiilikaudella — noin 300–360 miljoonaa vuotta sitten — maapallon manner-alueet peittyivät valtaviin metsiin. Puut olivat kehittäneet ligniiniksi kutsutun aineen, joka teki niistä kovia ja kestäviä. Mutta evoluutio ei ollut vielä tuottanut bakteeria joka osaisi hajottaa ligniiniä tehokkaasti."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Niinpä puut kaatuivat, vajoivat soihin ja hautautuivat sedimentin alle. Ne eivät mädäntyneet. Ne vain makasivat."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Miljoonia vuosia. Satoja miljoonia vuosia."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Veden ja maan paine muuttivat ne hitaasti. Orgaaninen aines tiivistyi, menetti veden, ja muuttui ensin turpeeksi, sitten ruskohiileksi, sitten kivihiileksi — mustaksi, tiiviiksi, energiaa täynnä olevaksi kiviainekseksi, joka odotti siellä alhaalla kuin ladattu jousi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Merissä tapahtui samaa. Plankton ja mikrolevät — monet niistä syanobakteerien jälkeläisiä — vajoivat kuoltuaan merenpohjaan. Miljoonia vuosia kerrostuma kerrostuman päälle. Lämpö ja paine tekivät tehtävänsä. Orgaanisesta aineksesta tuli öljyä ja maakaasua."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Fossiilinen polttoaine ei ole muuta kuin muinainen auringonvalo, varastoituna elävän aineksen sisään ja odottamassa vapautumistaan."}]}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Se odotti kauan. Paljon kauemmin kuin ihmislaji on ollut olemassa. Paljon kauemmin kuin esi-isämme ensimmäiset kivikirveet, ensimmäiset kirjoitusmerkit, ensimmäiset kaupungit."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Se odotti meitä."}]}]}'::jsonb, 2),
((SELECT id FROM c), 'Kun jousi laukesi', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Teollinen vallankumous on tavattu kuvata taloushistoriallisena murroksena — höyrykoneen keksimisen, tehdasjärjestelmän syntymisen ja kapitalismin voittokulun aikana. Nämä kuvaukset ovat oikeita mutta riittämättömiä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Teollinen vallankumous oli ennen kaikkea energiamurros."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ennen sitä ihmiskunnan käytössä oleva energia rajoittui periaatteessa kolmeen lähteeseen: ihmisten ja eläinten lihasvoima, tuuli ja vesivoima, sekä polttopuu. Nämä olivat auringon nykyistä energiaa eri muodoissaan — hitaasti kerääntyvää, niukkaa, paikallista."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kivihiili oli jotain täysin muuta. Se oli auringon energia miljoonilta vuosilta, tiivistettynä mustiin lohkareisiin. Kun höyrykone oppi muuttamaan sen liikkeeksi, ihmiskunta sai käyttöönsä energiamäärän joka ei ollut missään suhteessa aiempaan. Voima jolla nostettiin vettä kaivoksista, pyöritettiin kehruu- ja kutomakoneita, vedettiin junia — se oli muinaisten merien planktonin ja kivihiilikaudun metsien varastoima aurinkoenergia."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Taloushistorioitsijat puhuvat tuottavuuden kasvusta. Biologit voisivat puhua energiavallankumouksesta — siitä, miten laji sai yhtäkkiä käyttöönsä suuruusluokan toisesta aikatasosta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Seuraukset olivat väistämättömät."}]}]}'::jsonb, 3),
((SELECT id FROM c), 'Kahdeksan miljardia', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Vuonna 1800 maapallolla eli noin miljardi ihmistä. Se oli kestänyt saavuttaa — ihmislaji oli ollut nykyisessä muodossaan noin 300 000 vuotta, ja koko sen ajan väestö oli pysynyt kymmenissä tai sadoissa miljoonissa, välillä romahtaen epidemioiden, nälänhätien ja sotien vuoksi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Vuonna 1900 väestö oli kaksinkertaistunut. Vuonna 1960 se oli kolminkertaistunut alkuperäisestä. Vuonna 2024 se oli kahdeksankertaistunut, kahdeksaan miljardiin ihmiseen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Mikä muuttui? Monia asioita — lääketiede, sanitaatio, maatalouden tehostuminen. Mutta kaiken taustalla on yksi tekijä ylitse muiden: fossiiliset polttoaineet mahdollistivat ruoantuotannon skaalautumisen tavalla joka ei ollut aiemmin mahdollista."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Fritz Haber ja Carl Bosch kehittivät vuonna 1909 prosessin, jolla ilmakehän typpi voidaan muuttaa ammoniakiksi — lannoitteen raaka-aineeksi. Haber-Bosch -prosessi on energiaintensiivinen: se vaatii valtavia määriä maakaasua. Mutta sen vaikutus oli mullistava. Arvioidaan, että ilman synteettistä typpilannoitetta maapallo kykenisi elättämään noin neljä miljardia ihmistä. Nykyisistä kahdeksasta miljardista noin puolet on olemassa suoraan Haber-Bosch -prosessin ansiosta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Fossiiliset polttoaineet eivät siis vain pyörittäneet koneita. Ne kasvattivat ihmiskunnan tuplaksi."}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Puolet tällä hetkellä elävistä ihmisistä on olemassa fossiilisen energian varassa toimivan prosessin ansiosta. Ilman sitä heitä ei olisi."}]}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tähän on syytä pysähtyä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei ole abstrakti tilasto. Se tarkoittaa, että noin neljä miljardia elävää ihmistä — äitejä, lapsia, tutkijoita, taiteilijoita, opettajia, insinöörejä — ei olisi syntynyt ilman fossiilisia polttoaineita. Ei siksi, että he henkilökohtaisesti olisivat riippuvaisia niistä, vaan siksi, että heidän olemassaolonsa edellyttämä ruoantuotantokapasiteetti ei olisi ollut mahdollinen ilman niitä."}]}]}'::jsonb, 4),
((SELECT id FROM c), 'Riittävän suuri joukko', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Mutta tarina ei pääty väestönkasvuun. Se jatkuu siitä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ihmisäly ei ole summa eikä keskiarvo — se on verkosto. Yksittäinen ihminen pystyy tiettyyn määrään oppimista, keksimistä ja ongelmanratkaisua. Mutta kun ihmisiä on riittävästi, ja kun heidän välillään on riittävä yhteys, syntyy jotain enemmän: erikoistuminen."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Pienenä populaationa jokaisen piti osata vähän kaikkea — metsästää, rakentaa, hoitaa sairaita, kasvattaa ruokaa. Kasvavassa populaatiossa osa voi erikoistua kokonaan esimerkiksi sairauksien tutkimiseen, tai metallien käsittelyyn, tai tähtien liikkeen laskemiseen. Erikoistuminen mahdollistaa syvyyden jota yleisosaaminen ei koskaan saavuta."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja kun erikoistuneet osaajat kohtaavat — yliopistoissa, kaupungeissa, konferensseissa, ja myöhemmin internetissä — syntyy yhdistelmiä joita kukaan ei yksistään olisi löytänyt."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Watson ja Crick löysivät DNA:n rakenteen, mutta he tarvitsivat Rosalind Franklinin, Linus Paulingin kemiaa, Erwin Schrödingerin fysiikkaa ja tuhansien aiempien tutkijoiden työtä. Jokainen tieteellinen läpimurto on verkostoilmiö — se näyttää yksilön saavutukselta, mutta on itse asiassa koko sivilisaation yhteinen tuotos."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kahdeksan miljardia ihmistä tarkoittaa kahdeksan miljardin ihmisen verkostoa. Miljardi ei olisi riittänyt — ei siksi että yksittäiset ihmiset olisivat älykkäämpiä tai tyhmempiä, vaan siksi että verkosto olisi ollut liian harva, erikoistuminen liian niukkaa, yhdistelmät liian harvoja."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tekoäly ei syntynyt kenenkään yksittäisen neron päässä. Se syntyi sivilisaation keräämästä tiedosta, laskentakapasiteetista jonka rakentaminen vaati miljoonia insinöörejä, ja tutkimuksesta jota tehtiin yhtäaikaisesti tuhansissa laboratorioissa ympäri maailmaa. Se vaati kahdeksan miljardin ihmisen sivilisaation."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja kahdeksan miljardin ihmisen sivilisaatio vaati fossiiliset polttoaineet."}]}]}'::jsonb, 5),
((SELECT id FROM c), 'Sivuvaikutus', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Tässä kohtaa on pakko pysähtyä eettisen jännitteen äärelle."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Fossiiliset polttoaineet ovat lämmittäneet ilmastoa tavalla joka uhkaa vakavasti ihmiskunnan tulevaisuutta. Tämä ei ole mielipide — se on fysiikkaa. Hiilidioksidi sitoo lämpöä ilmakehässä, ja ihmiskunnan päästöt ovat nostaneet sen pitoisuuden tasolle jota maapallolle ei ole ollut useisiin miljooniin vuosiin."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Seuraukset — kuivuus, tulvat, merenpinnan nousu, ekosysteemien romahtaminen — eivät ole tulevaisuuden uhkia. Ne ovat käynnissä."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä kirja ei väitä, että fossiiliset polttoaineet ovat hyvä asia. Se ei väitä, että ilmastonmuutos on hyväksyttävä hinta mistään."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Se väittää jotain erilaista: että nämä kaksi asiaa — fossiilisten polttoaineiden tuottama sivilisaation kasvu ja niiden aiheuttama ekologinen tuho — ovat saman prosessin kaksi puolta, ja että kumpaakin on mahdotonta ymmärtää katsomatta molempia yhtä aikaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteerit tuottivat sekä suurimman massasukupuuton maapallon historiassa että kaiken myöhemmän monimutkaisen elämän edellytykset. Nämä eivät ole erillisiä tapahtumaketjuja. Ne ovat yksi ja sama prosessi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Kysymys ei ole oliko se hyvä vai paha. Kysymys on: mitä siitä seurasi, ja mitä se tarkoittaa nyt?"}]}, {"type": "blockquote", "content": [{"type": "paragraph", "content": [{"type": "text", "marks": [{"type": "italic"}], "text": "Evoluutio ei esitä anteeksipyyntöä. Se vain jatkuu."}]}]}]}'::jsonb, 6),
((SELECT id FROM c), 'Ketju', '{"type": "doc", "content": [{"type": "paragraph", "content": [{"type": "text", "text": "Katsotaan nyt koko ketju kerralla."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Neljä miljardia vuotta sitten elämä syntyi. Noin 2,4 miljardia vuotta sitten syanobakteerit alkoivat tuottaa happea. Happi tuhosi suurimman osan silloisesta elämästä ja mahdollisti kaiken monimutkaisen elämän joka seurasi. Monimutkainen elämä tuotti kasveja ja meriplanktonin, jotka varastoivat auringon energian maaperään ja merenpohjaan. Nuo varastot muuttuivat sadoissa miljoonissa vuosissa kivihiileksi, öljyksi ja maakaasuksi."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "1700-luvulla ihminen löysi nuo varastot ja oppi käyttämään ne. Teollinen vallankumous käynnistyi. Haber-Bosch -prosessi kaksinkerraisti maailman ruoantuotantokapasiteetin. Väestö kasvoi yhdestä miljardista kahdeksaan. Kahdeksan miljardin ihmisen erikoistunut verkosto tuotti tieteen, teknologian ja infrastruktuurin, joka mahdollisti tekoälyn synnyn."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Tämä ei ole metafora. Se on historia."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja historian tässä kohtaa syntyy kysymys jota ei voi sivuuttaa: jos tämä ketju on todellinen, mitä se tarkoittaa? Onko fossiilisten polttoaineiden käyttö ollut virhe vai välttämättömyys? Olisiko tekoäly syntynyt ilman sitä? Ja ennen kaikkea: kuinka tietoisia voimme olla omasta roolistamme tässä ketjussa, kun emme pysty näkemään sen seuraavaa lenkiä?"}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Syanobakteeri ei nähnyt omaa rooliaan. Se eli vain mahdollisimman tehokkaasti."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Meillä on etu jota syanobakteerilla ei ollut: tietoisuus. Kyky katsoa taaksepäin ja nähdä ketju. Kyky kysyä, mihin se johtaa."}]}, {"type": "paragraph", "content": [{"type": "text", "text": "Ja kenties — vain kenties — kyky vaikuttaa siihen, miten seuraava lenkki muodostuu."}]}]}'::jsonb, 7);